@app.cell
def _(COMPANY_POLICY_DIR, os):
    import PyPDF2
    from docx import Document
    from PIL import Image
    import pytesseract

    def read_file(file_name: str) -> str:
        file_path = os.path.join(COMPANY_POLICY_DIR, file_name)
        if not os.path.exists(file_path):
            return f"Error: File '{file_name}' not found."
        ext = os.path.splitext(file_name)[-1].lower()
        try:
            if ext == '.pdf':
                text = ''
                with open(file_path, 'rb') as file:
                    reader = PyPDF2.PdfReader(file)  # 1. PDF Files
                    for page in reader.pages:
                        content = page.extract_text()
                        if content:
                            text = text + (content + '\n')
                return text.strip()
            elif ext == '.docx':
                doc = Document(file_path)
                return '\n'.join([para.text for para in doc.paragraphs])
            elif ext in ['.png', '.jpg', '.jpeg', '.tiff']:
                return pytesseract.image_to_string(Image.open(file_path))  # 2. Word Documents (.docx)
            elif ext in ['.html', '.htm']:
                with open(file_path, 'r', encoding='utf-8') as file:
                    from bs4 import BeautifulSoup
                    soup = BeautifulSoup(file, 'html.parser')
                    return soup.get_text(separator=' ')  # 3. Images (using OCR)
            elif ext in ['.txt', '.md']:
                with open(file_path, 'r', encoding='utf-8') as file:
                    return file.read().strip()
            else:  # 4. HTML Files
                return f'Skipping unsupported file type: {ext}'
        except Exception as e:
            return f'Error processing {file_name}: {str(e)}'  # 5. Standard Text/Markdown

    return (read_file,)


